import dotenv from 'dotenv';

dotenv.config();

export interface Config {
  port: number;
  databasePath: string;

  // Twilio SMS Configuration
  twilioAccountSid: string;
  twilioAuthToken: string;
  twilioPhoneNumber: string;

  // Telegram Configuration
  telegramBotToken: string;

  // WhatsApp Configuration
  whatsappApiUrl: string;
  whatsappApiToken: string;
  whatsappPhoneNumberId: string;

  // Rate Limiting
  smsRateLimit: number; // messages per minute
  telegramRateLimit: number;
  whatsappRateLimit: number;

  // Retry Configuration
  maxRetries: number;
  retryBaseDelay: number; // milliseconds

  // Cache Configuration
  chartCacheDuration: number; // milliseconds

  // Timezone
  defaultTimezone: string;
}

const config: Config = {
  port: parseInt(process.env.PORT || '3000', 10),
  databasePath: process.env.DATABASE_PATH || './data/habits.db',

  twilioAccountSid: process.env.TWILIO_ACCOUNT_SID || '',
  twilioAuthToken: process.env.TWILIO_AUTH_TOKEN || '',
  twilioPhoneNumber: process.env.TWILIO_PHONE_NUMBER || '',

  telegramBotToken: process.env.TELEGRAM_BOT_TOKEN || '',

  whatsappApiUrl: process.env.WHATSAPP_API_URL || 'https://graph.facebook.com/v18.0',
  whatsappApiToken: process.env.WHATSAPP_API_TOKEN || '',
  whatsappPhoneNumberId: process.env.WHATSAPP_PHONE_NUMBER_ID || '',

  smsRateLimit: parseInt(process.env.SMS_RATE_LIMIT || '10', 10),
  telegramRateLimit: parseInt(process.env.TELEGRAM_RATE_LIMIT || '30', 10),
  whatsappRateLimit: parseInt(process.env.WHATSAPP_RATE_LIMIT || '80', 10),

  maxRetries: parseInt(process.env.MAX_RETRIES || '3', 10),
  retryBaseDelay: parseInt(process.env.RETRY_BASE_DELAY || '1000', 10),

  chartCacheDuration: parseInt(process.env.CHART_CACHE_DURATION || '300000', 10), // 5 minutes

  defaultTimezone: process.env.DEFAULT_TIMEZONE || 'UTC',
};

export default config;
